for (int i = 0; i < Iterations; i++)
    analyzer.AverageWordLength();
sw.Stop();
Console.WriteLine($"AverageWordLength:   {sw.Elapsed.TotalMilliseconds,10:F3} ms total | {sw.Elapsed.TotalNanoseconds / Iterations,8:F1} ns/op");

